+/**
+ * Email notification adapter — delivers notifications via email.
+ *
+ * This adapter implements the NotificationAdapter interface for the 'email'
+ * channel. It translates a NotificationPayload into an email delivery attempt.
+ *
+ * Current implementation: In-memory stub that logs email sends and records
+ * them for testing/auditing. Replace the `deliverEmail` method with a real
+ * SMTP or email API integration (e.g., SendGrid, SES, Postmark) for production.
+ *
+ * Constraints (from NotificationAdapter contract):
+ * - Must not throw exceptions; always returns a NotificationResult.
+ * - Must be stateless regarding notification data (sent emails are for audit only).
+ * - Must declare support for exactly one channel via `supports()`.
+ */
+
+import type {
+  NotificationAdapter,
+  NotificationChannel,
+  NotificationPayload,
+  NotificationResult,
+} from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+/**
+ * Represents an email message prepared for delivery.
+ */
+export interface EmailMessage {
+  /** Recipient email address. */
+  to: string;
+  /** Email subject line. */
+  subject: string;
+  /** Plain-text email body. */
+  body: string;
+  /** Optional recipient display name for the "To" header. */
+  recipientName?: string;
+  /** Timestamp when the email was queued. */
+  queuedAt: Date;
+}
+
+/**
+ * Configuration options for the EmailAdapter.
+ */
+export interface EmailAdapterConfig {
+  /** Sender email address (From header). */
+  fromAddress: string;
+  /** Sender display name. */
+  fromName: string;
+  /** Whether to actually attempt delivery (false = dry-run). */
+  enabled: boolean;
+}
+
+/** Default configuration for development/testing. */
+const DEFAULT_EMAIL_CONFIG: EmailAdapterConfig = {
+  fromAddress: 'noreply@taskflowpro.com',
+  fromName: 'TaskFlow Pro',
+  enabled: true,
+};
+
+/**
+ * Email notification adapter.
+ *
+ * Implements NotificationAdapter for the 'email' channel.
+ * Stores sent emails in memory for testing and audit purposes.
+ */
+export class EmailAdapter implements NotificationAdapter {
+  readonly name = 'EmailAdapter';
+  private logger = new Logger('EmailAdapter');
+  private config: EmailAdapterConfig;
+  private sentEmails: EmailMessage[] = [];
+
+  constructor(config?: Partial<EmailAdapterConfig>) {
+    this.config = { ...DEFAULT_EMAIL_CONFIG, ...config };
+  }
+
+  /**
+   * Returns the channel this adapter supports.
+   */
+  supports(): NotificationChannel {
+    return 'email';
+  }
+
+  /**
+   * Deliver a notification as an email.
+   *
+   * Translates the NotificationPayload into an EmailMessage and
+   * attempts delivery. Returns a NotificationResult indicating
+   * success or failure — never throws.
+   */
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    const timestamp = new Date();
+
+    if (!this.config.enabled) {
+      this.logger.info(`Email delivery disabled, skipping: ${payload.subject}`);
+      return {
+        success: false,
+        channel: 'email',
+        message: 'Email delivery is disabled',
+        timestamp,
+      };
+    }
+
+    if (!payload.recipient) {
+      this.logger.warn('Cannot send email: no recipient specified');
+      return {
+        success: false,
+        channel: 'email',
+        message: 'No recipient email address provided',
+        timestamp,
+      };
+    }
+
+    const email: EmailMessage = {
+      to: payload.recipient,
+      subject: payload.subject,
+      body: payload.body,
+      recipientName: payload.recipientName,
+      queuedAt: timestamp,
+    };
+
+    try {
+      await this.deliverEmail(email);
+      this.sentEmails.push(email);
+      this.logger.info(`Email sent to ${email.to}: ${email.subject}`);
+
+      return {
+        success: true,
+        channel: 'email',
+        message: `Email delivered to ${email.to}`,
+        timestamp,
+      };
+    } catch (err: unknown) {
+      const errorMessage = err instanceof Error ? err.message : 'Unknown email delivery error';
+      this.logger.error(`Email delivery failed for ${email.to}: ${errorMessage}`);
+
+      return {
+        success: false,
+        channel: 'email',
+        message: errorMessage,
+        timestamp,
+      };
+    }
+  }
+
+  /**
+   * Internal email delivery method — stub for now.
+   *
+   * Replace this with real SMTP or email API integration for production.
+   * This stub simply resolves immediately, simulating a successful send.
+   *
+   * @param _email - The email message to deliver.
+   */
+  protected async deliverEmail(_email: EmailMessage): Promise<void> {
+    // Stub: In production, integrate with an email provider here.
+    // Example: await smtpClient.send(email);
+    return Promise.resolve();
+  }
+
+  // ─── Testing & Audit Helpers ────────────────────────────────────────────
+
+  /**
+   * Get all emails that were successfully sent (in-memory audit log).
+   */
+  getSentEmails(): EmailMessage[] {
+    return [...this.sentEmails];
+  }
+
+  /**
+   * Get the count of successfully sent emails.
+   */
+  getSentCount(): number {
+    return this.sentEmails.length;
+  }
+
+  /**
+   * Clear the sent email audit log (useful for testing).
+   */
+  clearSentEmails(): void {
+    this.sentEmails = [];
+  }
+
+  /**
+   * Get the current adapter configuration.
+   */
+  getConfig(): Readonly<EmailAdapterConfig> {
+    return { ...this.config };
+  }
+}

