+import { describe, it, expect, beforeEach } from 'vitest';
+import { EmailAdapter } from '../../src/adapters/email.adapter.js';
+import type { NotificationPayload } from '../../src/models/notification.js';
+
+describe('EmailAdapter', () => {
+  let adapter: EmailAdapter;
+
+  beforeEach(() => {
+    adapter = new EmailAdapter();
+  });
+
+  describe('supports', () => {
+    it('should support the email channel', () => {
+      expect(adapter.supports()).toBe('email');
+    });
+  });
+
+  describe('name', () => {
+    it('should have the correct adapter name', () => {
+      expect(adapter.name).toBe('EmailAdapter');
+    });
+  });
+
+  describe('send', () => {
+    it('should successfully send an email', async () => {
+      const payload: NotificationPayload = {
+        type: 'order_confirmation',
+        recipient: 'alice@example.com',
+        recipientName: 'Alice',
+        subject: 'Order Confirmation',
+        body: 'Your order has been placed.',
