/**
 * Email notification adapter — delivers notifications via email.
 *
 * This adapter implements the NotificationAdapter interface for the 'email'
 * channel. It translates a NotificationPayload into an email delivery attempt.
 *
 * Current implementation: In-memory stub that logs email sends and records
 * them for testing/auditing. Replace the `deliverEmail` method with a real
 * SMTP or email API integration (e.g., SendGrid, SES, Postmark) for production.
 *
 * Constraints (from NotificationAdapter contract):
 * - Must not throw exceptions; always returns a NotificationResult.
 * - Must be stateless regarding notification data (sent emails are for audit only).
 * - Must declare support for exactly one channel via `supports()`.
 */

import type {
  NotificationAdapter,
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Represents an email message prepared for delivery.
 */
export interface EmailMessage {
  /** Recipient email address. */
  to: string;
  /** Email subject line. */
  subject: string;
  /** Plain-text email body. */
  body: string;
  /** Optional recipient display name for the "To" header. */
  recipientName?: string;
  /** Timestamp when the email was queued. */
  queuedAt: Date;
}

/**
 * Configuration options for the EmailAdapter.
 */
export interface EmailAdapterConfig {
  /** Sender email address (From header). */
  fromAddress: string;
  /** Sender display name. */
  fromName: string;
  /** Whether to actually attempt delivery (false = dry-run). */
  enabled: boolean;
}

/** Default configuration for development/testing. */
const DEFAULT_EMAIL_CONFIG: EmailAdapterConfig = {
  fromAddress: 'noreply@taskflowpro.com',
  fromName: 'TaskFlow Pro',
  enabled: true,
};

/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel.
 * Stores sent emails in memory for testing and audit purposes.
 */
export class EmailAdapter implements NotificationAdapter {
  readonly name = 'EmailAdapter';
  private logger = new Logger('EmailAdapter');
  private config: EmailAdapterConfig;
  private sentEmails: EmailMessage[] = [];

  constructor(config?: Partial<EmailAdapterConfig>) {
    this.config = { ...DEFAULT_EMAIL_CONFIG, ...config };
  }

  /**
   * Returns the channel this adapter supports.
   */
  supports(): NotificationChannel {
    return 'email';
  }

  /**
   * Deliver a notification as an email.
   *
   * Translates the NotificationPayload into an EmailMessage and
   * attempts delivery. Returns a NotificationResult indicating
   * success or failure — never throws.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const timestamp = new Date();

    if (!this.config.enabled) {
      this.logger.info(`Email delivery disabled, skipping: ${payload.subject}`);
      return {
        success: false,
        channel: 'email',
        message: 'Email delivery is disabled',
        timestamp,
      };
    }

    if (!payload.recipient) {
      this.logger.warn('Cannot send email: no recipient specified');
      return {
        success: false,
        channel: 'email',
        message: 'No recipient email address provided',
        timestamp,
      };
    }

    const email: EmailMessage = {
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      recipientName: payload.recipientName,
      queuedAt: timestamp,
    };

    try {
      await this.deliverEmail(email);
      this.sentEmails.push(email);
      this.logger.info(`Email sent to ${email.to}: ${email.subject}`);

      return {
        success: true,
        channel: 'email',
        message: `Email delivered to ${email.to}`,
        timestamp,
      };
    } catch (err: unknown) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown email delivery error';
      this.logger.error(`Email delivery failed for ${email.to}: ${errorMessage}`);

      return {
        success: false,
        channel: 'email',
        message: errorMessage,
        timestamp,
      };
    }
  }

  /**
   * Internal email delivery method — stub for now.
   *
   * Replace this with real SMTP or email API integration for production.
   * This stub simply resolves immediately, simulating a successful send.
   *
   * @param _email - The email message to deliver.
   */
  protected async deliverEmail(_email: EmailMessage): Promise<void> {
    // Stub: In production, integrate with an email provider here.
    // Example: await smtpClient.send(email);
    return Promise.resolve();
  }

  // ─── Testing & Audit Helpers ────────────────────────────────────────────

  /**
   * Get all emails that were successfully sent (in-memory audit log).
   */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /**
   * Get the count of successfully sent emails.
   */
  getSentCount(): number {
    return this.sentEmails.length;
  }

  /**
   * Clear the sent email audit log (useful for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }

  /**
   * Get the current adapter configuration.
   */
  getConfig(): Readonly<EmailAdapterConfig> {
    return { ...this.config };
  }
}

/**
 * Notification service — central hub for all notification delivery.
 *
 * Architecture: Event-driven via EventBus.
 *
 * This service listens to domain events (order:created, order:status-changed,
 * user:created, etc.) on the EventBus and translates them into notification
 * deliveries through registered adapters. It never receives notifications
 * through direct calls from other services.
 *
 * Flow:
 *   1. Domain service emits event → EventBus
 *   2. NotificationService handler picks up the event
 *   3. Handler builds a NotificationPayload
 *   4. NotificationService dispatches payload to matching adapters by channel
 *   5. NotificationService emits notification:sent or notification:failed events
 *
 * Constraints:
 * - All notifications MUST originate from EventBus domain events.
 * - All delivery adapters MUST implement the NotificationAdapter interface.
 * - Adapters are registered at construction time via dependency injection.
 * - The service never calls other services directly.
 * - Failed adapter deliveries are logged and emitted as events, not thrown.
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events and emitting lifecycle events
 * - NotificationAdapter implementations for channel-specific delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
} from '../events/event-types.js';
import type {
  Notification,
  NotificationAdapter,
  NotificationChannel,
  NotificationPayload,
  NotificationPriority,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter (for testing). */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

/**
 * Central notification service.
 *
 * Listens to domain events on the EventBus, builds notification payloads,
 * and dispatches them through registered channel adapters.
 */
export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private defaultChannels: NotificationChannel[] = ['email'];

  constructor(
    private eventBus: EventBus,
    adapters: NotificationAdapter[] = [],
  ) {
    for (const adapter of adapters) {
      this.registerAdapter(adapter);
    }
    this.registerEventHandlers();
  }

  // ─── Adapter Management ─────────────────────────────────────────────────

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel is supported; later registrations
   * replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    const channel = adapter.supports();
    this.adapters.set(channel, adapter);
    this.logger.info(`Registered adapter '${adapter.name}' for channel '${channel}'`);
  }

  /**
   * Get the adapter registered for a given channel, if any.
   */
  getAdapter(channel: NotificationChannel): NotificationAdapter | undefined {
    return this.adapters.get(channel);
  }

  /**
   * Get all registered channel names.
   */
  getRegisteredChannels(): NotificationChannel[] {
    return [...this.adapters.keys()];
  }

  // ─── Event Handlers (Domain Events → Notifications) ─────────────────────

  /**
   * Subscribe to all domain events that should trigger notifications.
   * New event handlers for additional domain events should be added here.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });

    this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
      return this.handleUserCreated(event);
    });
  }

  /**
   * Handle order:created — send order confirmation to the customer.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Handling order:created for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.dispatchNotification({
      type: 'order_confirmation',
      recipient: event.user.email,
      recipientName: event.user.name,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      priority: 'high',
      metadata: {
        orderId: event.order.id,
        userId: event.user.id,
      },
    });
  }

  /**
   * Handle order:status-changed — notify customer of status update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Handling order:status-changed for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    await this.dispatchNotification({
      type: 'order_status_update',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      priority: 'normal',
      metadata: {
        orderId: event.order.id,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    });
  }

  /**
   * Handle user:created — send a welcome notification.
   */
  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    this.logger.info(`Handling user:created for user ${event.user.id}`);

    await this.dispatchNotification({
      type: 'welcome',
      recipient: event.user.email,
      recipientName: event.user.name,
      subject: 'Welcome to TaskFlow Pro!',
      body: `Hi ${event.user.name}, welcome to TaskFlow Pro! Your account has been created.`,
      priority: 'normal',
      metadata: {
        userId: event.user.id,
      },
    });
  }

  // ─── Core Dispatch Logic ────────────────────────────────────────────────

  /**
   * Dispatch a notification payload to all applicable channel adapters.
   *
   * This is the central delivery method. It resolves which channels to use,
   * sends through each adapter, records the notification, and emits
   * lifecycle events.
   *
   * @param payload - The notification payload to deliver.
   * @returns Array of NotificationResults from each channel attempt.
   */
  async dispatchNotification(payload: NotificationPayload): Promise<NotificationResult[]> {
    const channels = payload.channels ?? this.defaultChannels;
    const priority: NotificationPriority = payload.priority ?? 'normal';
    const results: NotificationResult[] = [];

    // Emit notification:requested event before delivery
    await this.eventBus.emit({
      type: 'notification:requested',
      payload,
      channels,
      timestamp: new Date(),
    });

    for (const channel of channels) {
      const adapter = this.adapters.get(channel);

      if (!adapter) {
        // No adapter registered for this channel — record as failed
        this.logger.warn(`No adapter registered for channel '${channel}', skipping`);
        const notification = this.recordNotification(payload, channel, priority, 'failed', `No adapter for channel '${channel}'`);

        await this.eventBus.emit({
          type: 'notification:failed',
          notification,
          channel,
          error: `No adapter registered for channel '${channel}'`,
          timestamp: new Date(),
        });

        results.push({
          success: false,
          channel,
          message: `No adapter for channel '${channel}'`,
          timestamp: new Date(),
        });
        continue;
      }

      const result = await adapter.send(payload);
      results.push(result);

      if (result.success) {
        const notification = this.recordNotification(payload, channel, priority, 'sent');

        await this.eventBus.emit({
          type: 'notification:sent',
          notification,
          channel,
          timestamp: new Date(),
        });
      } else {
        const notification = this.recordNotification(
          payload,
          channel,
          priority,
          'failed',
          result.message,
        );

        await this.eventBus.emit({
          type: 'notification:failed',
          notification,
          channel,
          error: result.message ?? 'Unknown error',
          timestamp: new Date(),
        });
      }
    }

    return results;
  }

  // ─── Notification Record Management ─────────────────────────────────────

  /**
   * Record a notification in the in-memory store.
   */
  private recordNotification(
    payload: NotificationPayload,
    channel: NotificationChannel,
    priority: NotificationPriority,
    status: 'sent' | 'failed',
    errorMessage?: string,
  ): Notification {
    const now = new Date();
    const notification: Notification = {
      id: generateNotificationId(),
      type: payload.type,
      channel,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      status,
      priority,
      metadata: payload.metadata,
      createdAt: now,
      updatedAt: now,
      errorMessage,
    };
    this.notifications.push(notification);
    this.logger.info(
      `Notification ${notification.id} [${status}] via ${channel} to ${payload.recipient}`,
    );
    return notification;
  }

  /**
   * Get all notification records.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the total count of notification records.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notification records (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

