    it('should support the email channel', () => {
      expect(adapter.supports()).toBe('email');
    });
  });

  describe('name', () => {
    it('should have the correct adapter name', () => {
      expect(adapter.name).toBe('EmailAdapter');
    });
  });

  describe('send', () => {
    it('should successfully send an email', async () => {
      const payload: NotificationPayload = {
        type: 'order_confirmation',
        recipient: 'alice@example.com',
        recipientName: 'Alice',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('email');
      expect(result.message).toContain('alice@example.com');
      expect(result.timestamp).toBeInstanceOf(Date);
    });

    it('should record sent email in audit log', async () => {
      const payload: NotificationPayload = {
        type: 'welcome',
        recipient: 'bob@example.com',
        recipientName: 'Bob',
        subject: 'Welcome!',
        body: 'Welcome to the app.',
      };

      await adapter.send(payload);

      const sentEmails = adapter.getSentEmails();
      expect(sentEmails).toHaveLength(1);
      expect(sentEmails[0]?.to).toBe('bob@example.com');
      expect(sentEmails[0]?.subject).toBe('Welcome!');
      expect(sentEmails[0]?.body).toBe('Welcome to the app.');
      expect(sentEmails[0]?.recipientName).toBe('Bob');
    });

    it('should fail when delivery is disabled', async () => {
      const disabledAdapter = new EmailAdapter({ enabled: false });

      const payload: NotificationPayload = {
        type: 'system_alert',
        recipient: 'admin@example.com',
        subject: 'Alert',
        body: 'System alert.',
      };

      const result = await disabledAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.message).toContain('disabled');
      expect(disabledAdapter.getSentCount()).toBe(0);
    });

    it('should fail when recipient is empty', async () => {
      const payload: NotificationPayload = {
        type: 'system_alert',
        recipient: '',
        subject: 'Alert',
        body: 'System alert.',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.message).toContain('No recipient');
    });
  });

  describe('audit log management', () => {
    it('should count sent emails', async () => {
      expect(adapter.getSentCount()).toBe(0);

      await adapter.send({
        type: 'welcome',
        recipient: 'a@example.com',
        subject: 'Hi',
        body: 'Hello',
      });

      expect(adapter.getSentCount()).toBe(1);
    });

    it('should clear sent emails', async () => {
      await adapter.send({
        type: 'welcome',
        recipient: 'a@example.com',
        subject: 'Hi',
        body: 'Hello',
      });

      adapter.clearSentEmails();
      expect(adapter.getSentCount()).toBe(0);
    });

    it('should return a copy of sent emails', async () => {
      await adapter.send({
        type: 'welcome',
        recipient: 'a@example.com',
        subject: 'Hi',
        body: 'Hello',
      });

      const emails = adapter.getSentEmails();
      emails.pop();

      // Original should be unaffected
      expect(adapter.getSentCount()).toBe(1);
    });
  });

  describe('configuration', () => {
    it('should use default configuration', () => {
      const config = adapter.getConfig();
      expect(config.fromAddress).toBe('noreply@taskflowpro.com');
      expect(config.fromName).toBe('TaskFlow Pro');
      expect(config.enabled).toBe(true);
    });

    it('should accept custom configuration', () => {
      const customAdapter = new EmailAdapter({
        fromAddress: 'custom@example.com',
        fromName: 'Custom App',
      });

      const config = customAdapter.getConfig();
      expect(config.fromAddress).toBe('custom@example.com');
      expect(config.fromName).toBe('Custom App');
      expect(config.enabled).toBe(true); // default preserved
    });
  });
});
